1302 CorrelatedValuePropagationPass::run(Function &F, FunctionAnalysisManager &AM) {
1303   LazyValueInfo *LVI = &AM.getResult<LazyValueAnalysis>(F);
1304   DominatorTree *DT = &AM.getResult<DominatorTreeAnalysis>(F);
