551 // See if this min/max intrinsic always picks it's one specific operand.
552 // If not, check whether we can canonicalize signed minmax into unsigned version
553 static bool processMinMaxIntrinsic(MinMaxIntrinsic *MM, LazyValueInfo *LVI) {
554   CmpInst::Predicate Pred = CmpInst::getNonStrictPredicate(MM->getPredicate());
555   ConstantRange LHS_CR = LVI->getConstantRangeAtUse(MM->getOperandUse(0),
556                                                     /*UndefAllowed*/ false);
557   ConstantRange RHS_CR = LVI->getConstantRangeAtUse(MM->getOperandUse(1),
558                                                     /*UndefAllowed*/ false);
559   if (LHS_CR.icmp(Pred, RHS_CR)) {
560     ++NumMinMax;
561     MM->replaceAllUsesWith(MM->getLHS());
562     MM->eraseFromParent();
563     return true;
564   }
565   if (RHS_CR.icmp(Pred, LHS_CR)) {
566     ++NumMinMax;
567     MM->replaceAllUsesWith(MM->getRHS());
568     MM->eraseFromParent();
569     return true;
570   }
571 
572   if (MM->isSigned() &&
573       ConstantRange::areInsensitiveToSignednessOfICmpPredicate(LHS_CR,
574                                                                RHS_CR)) {
575     ++NumSMinMax;
576     IRBuilder<> B(MM);
577     MM->replaceAllUsesWith(B.CreateBinaryIntrinsic(
578         MM->getIntrinsicID() == Intrinsic::smin ? Intrinsic::umin
579                                                 : Intrinsic::umax,
580         MM->getLHS(), MM->getRHS()));
581     MM->eraseFromParent();
582     return true;
583   }
584 
585   return false;
586 }
