1806           (ICmpInst::Predicate)Pred, CI->getValue());
1807       if (TrueValues.contains(CR))
1808         return LazyValueInfo::True;
1809       if (TrueValues.inverse().contains(CR))
1810         return LazyValueInfo::False;
