1899   // Function entry or an unreachable block.  Bail to avoid confusing
1900   // analysis below.
1901   pred_iterator PI = pred_begin(BB), PE = pred_end(BB);
1902   if (PI == PE)
1903     return Unknown;
1904 
1905   // If V is a PHI node in the same block as the context, we need to ask
1906   // questions about the predicate as applied to the incoming value along
1907   // each edge. This is useful for eliminating cases where the predicate is
1908   // known along all incoming edges.
1909   if (auto *PHI = dyn_cast<PHINode>(V))
1910     if (PHI->getParent() == BB) {
1911       Tristate Baseline = Unknown;
1912       for (unsigned i = 0, e = PHI->getNumIncomingValues(); i < e; i++) {
1913         Value *Incoming = PHI->getIncomingValue(i);
1914         BasicBlock *PredBB = PHI->getIncomingBlock(i);
1915         // Note that PredBB may be BB itself.
1916         Tristate Result =
1917             getPredicateOnEdge(Pred, Incoming, C, PredBB, BB, CxtI);
1918 
1919         // Keep going as long as we've seen a consistent known result for
1920         // all inputs.
1921         Baseline = (i == 0) ? Result /* First iteration */
1922                             : (Baseline == Result ? Baseline
1923                                                   : Unknown); /* All others */
1924         if (Baseline == Unknown)
1925           break;
1926       }
1927       if (Baseline != Unknown)
1928         return Baseline;
1929     }
1930 
1931   // For a comparison where the V is outside this block, it's possible
1932   // that we've branched on it before. Look to see if the value is known
1933   // on all incoming edges.
1934   if (!isa<Instruction>(V) || cast<Instruction>(V)->getParent() != BB) {
1935     // For predecessor edge, determine if the comparison is true or false
1936     // on that edge. If they're all true or all false, we can conclude
1937     // the value of the comparison in this block.
1938     Tristate Baseline = getPredicateOnEdge(Pred, V, C, *PI, BB, CxtI);
1939     if (Baseline != Unknown) {
1940       // Check that all remaining incoming values match the first one.
1941       while (++PI != PE) {
1942         Tristate Ret = getPredicateOnEdge(Pred, V, C, *PI, BB, CxtI);
1943         if (Ret != Baseline)
1944           break;
1945       }
1946       // If we terminated early, then one of the values didn't match.
1947       if (PI == PE) {
1948         return Baseline;
1949       }
1950     }
1951   }
1952 
1953   return Unknown;
1954 }
